import { apiClient, unwrap, type BffResponse } from '../api';
import type {
  CostSheetDto,
  CostElementDto,
  CostSheetFilter,
  PagedResult,
  WipBalanceDto,
} from './models';
import type {
  DocumentPostEnqueueResult,
  DocumentPostingStatusResult,
  DocumentPostedLedgerDto,
} from '../kt/models';

const BASE = '/costing';

export const gtEndpoint = {
  getCostSheets: async (filter?: CostSheetFilter) => {
    const qs = new URLSearchParams();
    if (filter?.month) qs.set('month', String(filter.month));
    if (filter?.year) qs.set('year', String(filter.year));
    if (filter?.processingLevel) qs.set('processingLevel', filter.processingLevel);
    qs.set('page', String(filter?.page ?? 1));
    qs.set('pageSize', String(filter?.pageSize ?? 100));
    const res = await apiClient.get<BffResponse<PagedResult<CostSheetDto>>>(`${BASE}/cost-sheets?${qs}`);
    return unwrap(res);
  },
  getCostSheet: async (id: string) => {
    const res = await apiClient.get<BffResponse<CostSheetDto>>(`${BASE}/cost-sheets/${id}`);
    return unwrap(res);
  },
  getCostElements: async (id: string) => {
    const res = await apiClient.get<BffResponse<CostElementDto[]>>(`${BASE}/cost-sheets/${id}/elements`);
    const data = unwrap(res);
    return Array.isArray(data) ? data : [];
  },
  calculateCosts: async (month: number, year: number) => {
    const res = await apiClient.post<BffResponse<boolean>>(`${BASE}/cost-sheets/calculate`, { month, year });
    return unwrap(res);
  },
  approveCostSheet: async (id: string) => {
    const res = await apiClient.post<BffResponse<boolean>>(`${BASE}/cost-sheets/${id}/approve`);
    return unwrap(res);
  },
  postCostSheet: async (id: string) => {
    const res = await apiClient.post<BffResponse<DocumentPostEnqueueResult>>(`${BASE}/cost-sheets/${id}/post`);
    return unwrap(res);
  },
  getCostSheetPostingStatus: async (id: string) => {
    const res = await apiClient.get<BffResponse<DocumentPostingStatusResult>>(`${BASE}/cost-sheets/${id}/posting-status`);
    return unwrap(res);
  },
  getCostSheetPostedLedger: async (id: string) => {
    const res = await apiClient.get<BffResponse<DocumentPostedLedgerDto>>(`${BASE}/cost-sheets/${id}/posted-ledger`);
    return unwrap(res);
  },
  getWipBalance: async (params: { month?: number; year?: number }) => {
    const qs = new URLSearchParams();
    if (params.month) qs.set('month', String(params.month));
    if (params.year) qs.set('year', String(params.year));
    const res = await apiClient.get<BffResponse<WipBalanceDto[]>>(`${BASE}/wip-balance?${qs}`);
    const data = unwrap(res);
    return Array.isArray(data) ? data : [];
  },
};
